struct Transaction {
    let from: String
    let to: String
    let amount: Double
    let nonce: Int
    let gasPrice: Int
    let gasLimit: Int
    let chainId: Int
}

enum WalletCrypto {
    static func generatePrivateKey() -> Data {
        var bytes = [UInt8](repeating: 0, count: 32)
        _ = SecRandomCopyBytes(kSecRandomDefault, bytes.count, &bytes)
        return Data(bytes)
    }
    
    static func address(fromPrivateKey privateKey: Data) -> String {
        let hash = SHA256.hash(data: privateKey)
        let hex = Data(hash).hexString
        return "0x" + hex.prefix(40)
    }
    
    static func sign(transaction: Transaction, privateKey: Data) -> String {
        let payload = "\(transaction.from)|\(transaction.to)|\(transaction.amount)|\(transaction.nonce)|\(transaction.gasPrice)|\(transaction.gasLimit)|\(transaction.chainId)"
        let key = SymmetricKey(data: SHA256.hash(data: privateKey))
        let signature = HMAC<SHA256>.authenticationCode(for: Data(payload.utf8), using: key)
        return Data(signature).hexString
    }
}

final class BlockchainAPI {
    static let shared = BlockchainAPI()
    private init() {}
    
    func fetchBalance(address: String) async throws -> Double {
        guard let url = URL(string: "https://example.com/api/balance?address=\(address)") else {
            throw URLError(.badURL)
        }
        let (_, _) = try await URLSession.shared.data(from: url)
        return Double.random(in: 0...10)
    }
    
    func broadcastSignedTransaction(rawTransactionHex: String) async throws -> String {
        guard let url = URL(string: "https://example.com/api/broadcast") else {
            throw URLError(.badURL)
        }
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        let body: [String: String] = ["rawTransaction": rawTransactionHex]
        request.httpBody = try JSONSerialization.data(withJSONObject: body)
        let (_, _) = try await URLSession.shared.data(for: request)
        return Data(SHA256.hash(data: Data(rawTransactionHex.utf8))).hexString
    }
}

enum KeychainHelper {
    static func save(service: String, account: String, data: String) {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: account,
            kSecValueData as String: Data(data.utf8)
        ]
        SecItemDelete(query as CFDictionary)
        SecItemAdd(query as CFDictionary, nil)
    }
    
    static func read(service: String, account: String) -> String? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: account,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        var result: CFTypeRef?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        guard status == errSecSuccess,
              let data = result as? Data,
              let string = String(data: data, encoding: .utf8) else {
            return nil
        }
        return string
    }
}

extension Data {
    init?(hexString: String) {
        let cleaned = hexString.replacingOccurrences(of: "0x", with: "")
        guard cleaned.count % 2 == 0 else { return nil }
        var data = Data(capacity: cleaned.count / 2)
        var index = cleaned.startIndex
        while index < cleaned.endIndex {
            let nextIndex = cleaned.index(index, offsetBy: 2)
            guard let byte = UInt8(cleaned[index..<nextIndex], radix: 16) else { return nil }
            data.append(byte)
            index = nextIndex
        }
        self = data
    }
    
    var hexString: String {
        map { String(format: "%02x", $0) }.joined()
    }
}